import pickle,sys
segs=pickle.load(open('/tmp/segs.pkl','rb'))
mode=sys.argv[1]
def coords(s):
    z,x0,y0,x1,y1=s
    if mode=='yz': return (y0,z),(y1,z)
    if mode=='xy': return (x0,y0),(x1,y1)
pts=[]
for s in segs:
    a,b=coords(s); pts+=[a,b]
A=[p[0] for p in pts];B=[p[1] for p in pts]
minx,maxx=min(A),max(A);miny,maxy=min(B),max(B)
W=150;H=45
grid=[[' ']*W for _ in range(H)]
def px(x,y):
    return int((x-minx)/(maxx-minx)*(W-1)),int((y-miny)/(maxy-miny)*(H-1))
for s in segs:
    (x0,y0),(x1,y1)=coords(s)
    for i in range(11):
        t=i/10
        gx,gy=px(x0+(x1-x0)*t,y0+(y1-y0)*t)
        grid[H-1-gy][gx]='#'
print('\n'.join(''.join(r) for r in grid))
EOF
